def V_k_basis(k):
    if 1 <= k < N_int:
        return [
            ctx["x_0"] - ctx["x_star"],
            ctx[f"x_{k}"] - ctx["x_star"],
            h.grad(ctx["x_0"]),
            h.grad(ctx[f"x_{k}"]),
        ]
    if k == N_int:
        return [ctx["x_0"] - ctx["x_star"], h.grad(ctx["x_0"])]
    return []

def V_k_basis_labels(k):
    if 1 <= k < N_int:
        return ["x_0 - x_star", f"x_{k} - x_star", "grad_h(x_0)", f"grad_h(x_{k})"]
    if k == N_int:
        return ["x_0 - x_star", "grad_h(x_0)"]
    return []

coeff_code:
def coeff_pattern(k, N, alpha):
    c = sp.S(1) / (2 * alpha * N)
    if 1 <= k < N:
        C = sp.zeros(4, 4)
        C[0, 2] = C[2, 0] = -c
        C[1, 3] = C[3, 1] = c
        return C
    if k == N:
        C = sp.zeros(2, 2)
        C[0, 1] = C[1, 0] = -c
        return C
    return sp.zeros(0, 0)
